var src = inputs.Length > 0 ? inputs[0] : null;
    if (src == null)
        return new PixelBuffer(context.TileSize, context.TileSize);

    var threshold = GetFloat(parameters, "brightnessThreshold", 0.5f);
    var glowIntensity = GetFloat(parameters, "glowIntensity", 0.5f);
    var radius = Math.Max(1, (int)GetFloat(parameters, "glowRadius", 3f));
    var glowType = GetChoice(parameters, "glowType", "soft");
    var mixRatio = GetFloat(parameters, "mixRatio", 1f);
    var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

    var size = context.TileSize;
    var result = new PixelBuffer(size, size);

    // Step 1: Extract bright areas
    var bright = new PixelBuffer(size, size);
    bright.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, _) = src.GetPixel(x, y);
        var luminance = 0.299f * r + 0.587f * g + 0.114f * b;

        if (luminance > threshold)
        {
            var intensity = (luminance - threshold) / (1f - threshold);
            bright.SetPixel(x, y,
                MathF.Pow(r * intensity, 1.2f),
                MathF.Pow(g * intensity, 1.2f),
                MathF.Pow(b * intensity, 1.2f), 1f);
        }
        else
        {
            bright.SetPixel(x, y, 0, 0, 0, 1f);
        }
    });

    // Step 2: Blur the bright areas
    var glowBuffer = new PixelBuffer(size, size);
    GaussianBlur(bright, glowBuffer, radius, size);

    // Step 3: Compose
    result.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);
        var (gr, gg, gb, _) = glowBuffer.GetPixel(x, y);

        float outR, outG, outB;

        switch (glowType)
        {
            case "hardLight":
            {
                // Screen blend
                outR = 1f - (1f - r) * (1f - gr * glowIntensity);
                outG = 1f - (1f - g) * (1f - gg * glowIntensity);
                outB = 1f - (1f - b) * (1f - gb * glowIntensity);
                break;
            }
            case "edgeGlow":
            {
                // Only glow where there's a transition
                var edge = MathF.Abs(gr - r) * 2f;
                outR = r + edge * glowIntensity;
                outG = g + edge * glowIntensity * 0.8f;
                outB = b + edge * glowIntensity * 0.6f;
                break;
            }
            case "neon":
            {
                // Vivid colored glow
                outR = r + gr * glowIntensity * 0.8f;
                outG = g + gg * glowIntensity * 0.5f;
                outB = b + gb * glowIntensity * 1.2f;
                break;
            }
            default: // soft
            {
                outR = r + gr * glowIntensity * 0.5f;
                outG = g + gg * glowIntensity * 0.5f;
                outB = b + gb * glowIntensity * 0.5f;
                break;
            }
        }

        // Mix with original
        if (mixRatio < 0.999f)
        {
            outR = r + (outR - r) * mixRatio;
            outG = g + (outG - g) * mixRatio;
            outB = b + (outB - b) * mixRatio;
        }

        result.SetPixel(x, y,
            Math.Clamp(outR, 0f, 1f),
            Math.Clamp(outG, 0f, 1f),
            Math.Clamp(outB, 0f, 1f),
            preserveAlpha ? a : 1f);
    });

    return result;

private static void GaussianBlur(PixelBuffer src, PixelBuffer dst, int radius, int size)
{
    var sigma = radius * 0.5f + 0.5f;
    var temp = new PixelBuffer(size, size);
    var kernelSize = radius * 2 + 1;
    var kernel = new float[kernelSize];
    var sum = 0f;
    for (var i = 0; i < kernelSize; i++)
    {
        var dx = i - radius;
        kernel[i] = MathF.Exp(-(dx * dx) / (2f * sigma * sigma));
        sum += kernel[i];
    }
    var invSum = 1f / sum;

    temp.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f;
        for (var i = 0; i < kernelSize; i++)
        {
            var (pr, pg, pb, _) = src.GetPixelWrapped(x + i - radius, y);
            var w = kernel[i] * invSum;
            sumR += pr * w; sumG += pg * w; sumB += pb * w;
        }
        temp.SetPixel(x, y, sumR, sumG, sumB, 1f);
    });

    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f;
        for (var i = 0; i < kernelSize; i++)
        {
            var (pr, pg, pb, _) = temp.GetPixelWrapped(x, y + i - radius);
            var w = kernel[i] * invSum;
            sumR += pr * w; sumG += pg * w; sumB += pb * w;
        }
        dst.SetPixel(x, y, sumR, sumG, sumB, 1f);
    });
    }
}
